import React from "react";
import styles from "./ProdactCard.module.css";
import Image from "next/image";
import { Product } from "../types";

interface ProductDetailsProps {
  product: Product;
  onClose: () => void;
}

export const ProductDetails: React.FC<ProductDetailsProps> = ({ product, onClose }) => {
  return (
    <div className={styles.detailsOverlay} onClick={onClose}>
      <div className={styles.detailsModal} onClick={e => e.stopPropagation()}>
        <div className={styles.detailsContent}>
          <div className={styles.detailsImageWrap}>
            <Image src={product.image} alt={product.title} width={220} height={220} className={styles.detailsImage} />
          </div>
          <div className={styles.detailsInfo}>
            <h2 className={styles.detailsTitle}>{product.title}</h2>
            <div className={styles.detailsDesc}>{product.description}</div>
            <div className={styles.detailsStock}><b>У наявності:</b> {product.stock} шт</div>
            <div className={styles.detailsColor}><b>Колір:</b> білий</div>
            <div className={styles.detailsPriceRow}>
              <button className={styles.addButton}>+</button>
              <span className={styles.price}>{product.price}$</span>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};
